# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import Counter

app = Flask(__name__)

# Store labeled data
labeled_data = []

@app.route('/label', methods=['POST'])
def label_image():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']

    # Add label to labeled data
    labeled_data.append((image_id, label))

    return jsonify({'status': 'success'})

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    # Aggregate labels using majority voting
    aggregated_labels = {}
    for image_id, label in labeled_data:
        if image_id not in aggregated_labels:
            aggregated_labels[image_id] = Counter([label])
        else:
            aggregated_labels[image_id][label] += 1

    # Return aggregated labels
    return jsonify(aggregated_labels)

if __name__ == '__main__':
    app.run(debug=True)